var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"최근 영화 산업은 한 신예 감독의 작품에 주목하고 있다.","JPN":"最近の映画産業は、とある新鋭監督の作品に注目している。","ENG":"Recently, the film industry is taking notice of a work of a rookie director.","TWN":"最近在電影界，有一位新銳導演的作品相當受到矚目。"},"stage":{"bg":"FALLEN_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 영화는 흔한 개성의 작가주의가 만연하던 영화계에 참신한 충격을 선사했다.","JPN":"この映画は、ありふれた個性の作家主義が蔓延していた映画界に新鮮な衝撃を与えた。","ENG":"The movie was a fresh shock to the auteurism prevalent film industry.","TWN":"這部電影跳脫制式的框架，為電影界注入一股嶄新的氛圍。"},"stage":{"bg":"FALLEN_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"세계적인 드라마, 유혹의 함교 리허설 세트에서 벌어진 사건을 담아낸 이 영화는 싸구려 캠코더 한 대로 전부 촬영한 것 같은 올드 스타일의 다큐멘터리 기법을 사용하고 있다.","JPN":"グローバルなドラマ、誘惑の艦橋のリハーサルセットで発生した事件を収録したこの映画は、安物のビデオカメラ1台で全て撮影したようなオールドスタイルのドキュメンタリー制作手法を使用している。","ENG":"Filmed on the set of the popular TV series \\"The Bridge of Seduction\\", this movie uses an old-style documentary technique as if it has been filmed entirely with a cheap camcorder.","TWN":"戲裡在講述全球知名連續劇 誘惑的艦橋，在排演時發生的事件，全程只使用一台便宜的攝影機，以懷舊的紀錄片手法拍攝而成。"},"stage":{"bg":"FALLEN_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"인공적인 첨가물이 전혀 느껴지지 않는 리얼한 전투 CG와 카메라 뒤편에서 벌어지는 배우 후보들 간의 경쟁은 물질만능이라는 다소 직설적인 주제의식으로 많은 평론가들의 고개를 끄덕이게 만든다.","JPN":"人工的な作り物感がまったく感じられないリアルな戦闘CGと、カメラの裏で繰り広げられる女優候補たちの争いは、物質万能という多少直接的なテーマで多くの評論家たちをうなずかせる。","ENG":"The realistic CGI in battle and rivalry between the candidates behind the scenes all portray a theme of materialism and are enough to make critics hand out good marks.","TWN":"沒有任何後製處理的真實戰鬥CG，和鏡頭外演員之間的明爭暗鬥，皆受到許多影評的好評。"},"stage":{"bg":"FALLEN_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"영화와 다큐멘터리, 연기와 현실의 교묘한 간극, 늑대인간과 뱀파이어!","JPN":"映画とドキュメンタリー、演技と現実の絶妙な狭間、ライカンスロープとヴァンパイア！","ENG":"The slight rift between Movie and documentary, and acting and reality. Lycanthrope and Vampire!","TWN":"電影和紀錄片、演戲和現實之前巧妙的結合，還有狼人和吸血鬼！"},"stage":{"bg":"FALLEN_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"이 모든 것이 한 작가의 머릿속에서 나왔다고는 믿기 힘든…","JPN":"このすべてが作家1人の頭の中で生まれたとは信じられないほどの……","ENG":"It’s hard to believe that a single person thought of the whole plot...","TWN":"沒想到這些題材，全是從一位編劇的腦袋裡蹦出來的…"},"stage":{"bg":"FALLEN_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"멋지군요. 이번 출품작에 대한 기사들이 하나 같이 호평일색으로 가득합니다, 주인님.","JPN":"素晴らしい。今回の出品作についての記事が全部大好評です、ご主人様。","ENG":"Splendid. The articles about your entry are full of compliments, Mistress.","TWN":"主人好厲害！這次的作品受到新聞一致的好評呢！"},"stage":{"bg":"CAFE","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"처음부터 이 모든 상황을 카메라로 찍을 계획이셨던 건가요?","JPN":"最初からこのすべての状況をカメラに収めるつもりだったのですか？","ENG":"Did you plan to film the whole situation from the beginning?","TWN":"您從一開始就計畫要把這一切都拍下來嗎？"},"stage":{"bg":"CAFE","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"그래, 그 의뢰인이 찾아올 때부터 재미있는 사건의 냄새가 풍기더구나.","JPN":"ああ、あの依頼人が来た時から面白い事件のニオイがしたのじゃ。","ENG":"Yes, I sensed this was going to be a fun event when that client visited us.","TWN":"沒錯，那個委託人上門時，我就聞到一股有趣的味道。"},"stage":{"bg":"CAFE","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"그 옹졸한 자존심을 적당히 자극했더니 꽤나 괜찮은 그림이 나왔지.","JPN":"あの卑劣なプライドを適当に刺激したら、なかなか良い絵が撮れた。","ENG":"Stimulating her petty pride resulted in quite a film.","TWN":"我不過就稍微刺激一下她那小小的自尊心，結果拍出很不錯的畫面呢！"},"stage":{"bg":"CAFE","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"역시 주인님이십니다.","JPN":"さすがご主人様。","ENG":"This is why I respect you, Mistress.","TWN":"真不愧是主人。"},"stage":{"bg":"CAFE","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"의뢰인께서 이번 일로 배우의 은퇴를 결정한 건 안타까운 일이지만, 은퇴작으로선 부족함이 없겠군요.","JPN":"依頼人が今回のことで女優としての引退を決めたのは残念ですが、引退作品としては十分でしょう。","ENG":"It’s a pity that the client decided to retire as an actress, but I believe this would be more than enough for her last work.","TWN":"雖然很遺憾委託人因為這次的事件，決定不再當演員，但這也算是很完美的告別作。"},"stage":{"bg":"CAFE","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"그녀석을 계속 따라다니면 더 재미있는 일도 생길 것 같다만…","JPN":"あいつにずっと目をつけていれば、もっと面白いことが起きそうじゃが……","ENG":"I thought we would run into even more interesting events if we kept following her...","TWN":"繼續跟拍她的話，應該還會發生許多有趣的事情…"},"stage":{"bg":"CAFE","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"그건 내가 귀찮으니 사양이다.","JPN":"それは妾が面倒くさいから遠慮する。","ENG":"But that would be too much work.","TWN":"但我覺得有點麻煩。"},"stage":{"bg":"CAFE","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"시종? 간만에 이 몸의 창작욕구도 해소하고 돈도 벌었겠다, 기념으로 간만에 스테이크나…","JPN":"僕？　久々に妾の創作欲を解消してお金も稼いたところで、記念としてステーキを……","ENG":"Servant? Now that I satisfied my desire for creation, and now that we have money, shouldn’t we celebrate with some steak–","TWN":"僕人？難得可以滿足我的創作欲望，還賺到錢，不如就久違地來個牛排慶祝…"},"stage":{"bg":"CAFE","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"…음?","JPN":"……うむ？","ENG":"...Hmm?","TWN":"…嗯？"},"stage":{"bg":"CAFE","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_PRACTICE","text":{"KOREA":"저기… 안녕하세요?","JPN":"あの……こんにちは。","ENG":"Um... Hello?","TWN":"請問…有人在嗎？"},"stage":{"bg":"CAFE","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"의뢰인이냐? 아쉽겠지만 오늘은 의뢰를 받을 생각이 없으니 돌아가도록.","JPN":"依頼人か？　残念じゃが、今日は依頼を受け付ける気はないから帰るのじゃ。","ENG":"Are you here to make a commission? I’m sorry, but we’re closed for the day.","TWN":"是委託人嗎？真可惜，今天不接受委託咧，你回去吧！"},"stage":{"bg":"CAFE","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_PRACTICE","text":{"KOREA":"아, 아뇨. 전 그러니까… 감사인사를 드리고 싶어서 왔어요.","JPN":"い、いいえ。私は、えっと……感謝を伝えたくてやってきました。","ENG":"N-No. I just wanted... to thank you.","TWN":"不是的，我…是來道謝的。"},"stage":{"bg":"CAFE","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"감사인사?","JPN":"感謝を？","ENG":"Thank us?","TWN":"道謝？"},"stage":{"bg":"CAFE","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};